var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 저 괴물은 대체…….","JPN":"副学会長様、あの怪物はいったい……","ENG":"Vice President, what is that thing...?","TWN":"副學會長，那個怪物究竟……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레지. 나.</color>","JPN":"<color=#ff3636>レジー、ナ。</color>","ENG":"<color=#ff3636>Regi. Na.</color>","TWN":"<color=#ff3636>蕾·佳·娜。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L6_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님! 괴물이 다가와요! 정신 차리세요!","JPN":"副学会長様！　怪物が近づいてきます！　お気を確かに！","ENG":"Vice President! It's coming this way! Run!","TWN":"副學會長！怪物過來了！你醒醒啊！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아……. 하…… 하아…….","JPN":"はあ……は……はあ……","ENG":"*Huff...* *Huff...* *Huff...*","TWN":"呼呼……呼……呼呼……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"안 돼. 손가락 하나 까딱 못하겠어.","JPN":"ダメ。指ひとつ動かせないわ。","ENG":"Why... Why can I not move...?","TWN":"不行。手指動不了了。"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"침식체도, 잔해도 아무렇지 않았는데…… 저건 어디서 나타난 괴물이지?","JPN":"侵食体でも、残骸でも何ともなかったのに……あれはどこから来た怪物なの？","ENG":"I was not like this when I encountered a C.O. or the Remains... But where did that monster even come from?","TWN":"既不是侵蝕體，也不是殘骸……那東西究竟是從哪裡來的怪物？"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"움직여야 돼. 움직이지 않으면 죽어.","JPN":"動かないと。動かないと死ぬ。","ENG":"Please move... If I do not, I will die.","TWN":"必須動起來。不動就得死。"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 움직인다고 뭐가 달라질까? 저런 것에게서 내가 도망칠 수 있을까?","JPN":"でも動けたとして何ができるの？　あんな怪物から逃げられるとでも？","ENG":"But will it change anything? Will I be able to run away from it?","TWN":"可是就算能動，又有什麼區別呢？我能從那東西手中逃脫嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……살아나갈 수가, 있을까?","JPN":"……生きて出られる、かしら？","ENG":"Will I... be able to make it out alive?","TWN":"……我能，活下去嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>아아아아……!! </color>","JPN":"<color=#ff3636>アアアア……！！</color>","ENG":"<color=#ff3636>Ahhhh...!!</color>","TWN":"<color=#ff3636>啊啊啊啊……！！</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"다들 지금이야! 한눈 팔고 있는 사이에 혼쭐을 내 주자!","JPN":"みんな、今だよ！　よそ見をしている間にやってしまえ！","ENG":"NOW! Give it hell while it's distracted!","TWN":"就是現在！趁著它分神，好好教訓它吧！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"총알이…… 공중에서 멈춰 버린다고?","JPN":"銃弾が……空中で止まるだと？","ENG":"The bullets... It stopped them mid-air?!","TWN":"子彈……停在空中了？"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"대체 무슨 침식체지? 생포해서 연구해야 할 텐데!","JPN":"いったいどんな侵食体なんだ？　生け捕りにして研究しなければ！","ENG":"What kind of C.O. is it? We should capture it and research it!","TWN":"究竟是什麼侵蝕體呢？應該活捉研究一下！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"치이……. 귀찮은 녀석이네.","JPN":"ちいっ……めんどくさいやつ。","ENG":"Tch...! This isn't good.","TWN":"嘖……真是個麻煩的傢伙。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"앗, 부학회장이다! 쟨 또 왜 방에서 기어나와 있어?!","JPN":"あっ、副学会長！　ったく、なんでまた部屋から抜け出してるんだよ！？","ENG":"Huh? It's the Vice President! Why did she even leave her room again?!","TWN":"啊，是副學會長！她怎麼又從房間裡跑出來了？！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"啊……"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 정신이 드세요? 갑자기 우두커니 서 계셔서 깜짝 놀랐어요.","JPN":"副学会長様、気がつかれましたか？　突然立ったまま呆然とされて、驚きました。","ENG":"Ma'am, are you okay? You just suddenly froze, and it scared me.","TWN":"副學會長，你清醒了嗎？你突然愣愣地站著，嚇了我一跳。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"미, 미안해요. 실키. 저 괴물과는 아무래도 상성이 나쁜 모양이네요.","JPN":"ご、ごめんなさい。シルキー。どうやらあの怪物とは相性が良くないようですわ。","ENG":"S-sorry, Sylkie. I suppose this monster and I are not a good match.","TWN":"對…對不起，思琪。看來我無法克制那個怪物。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭘 태평하게 서 있어, 부학회장! 얼른 침실로 들어가!","JPN":"何を呑気に立ってるんだよ、副学会長！　早く寝室に戻りな！","ENG":"What are you standing around here for?! Go back to your room, Vice President!","TWN":"還站在這裡幹嘛，副學會長！快點回臥室！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 바보인 줄 알아요?! 복도에서 전투가 벌어지는 마당에 얌전히 있을 리가요!","JPN":"私はバカだと思っているのですか！？　廊下で戦闘が繰り広げられているのに、大人しくしていられるわけがありませんわ！","ENG":"Do you think I am daft?! How can I stay quietly in my room when this is happening right outside it?!","TWN":"你以為我是傻瓜嗎？！走廊裡發生了打鬥，我怎麼可能會乖乖待著！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭐어?! 야! 너 거기 안 서?!","JPN":"はあ！？　おい！　待ちなってば！！","ENG":"WHAAAT?! Hey! Stop right there, you!!","TWN":"什麼？！喂！你給我站住？！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"루나 님, 위험합니다! 물러나십시오!","JPN":"ルナ様、危険です！　お下がりください！","ENG":"Ms. Luna! It's too dangerous! Please step back!","TWN":"露娜，危險！你快退後！"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"엣.","JPN":"えっ。","ENG":"Oof...!","TWN":"呀。"},"stage":{"bg":"CORRIDOR_06","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레. 지나. 어. 디 있. 어?</color>","JPN":"<color=#ff3636>レ。ジーナ。ド、コニイ、ル？</color>","ENG":"<color=#ff3636>Where. Is. Re. Gina?</color>","TWN":"<color=#ff3636>蕾·佳娜·在·哪·裡？</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L46_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"루, 루나 님을 단번에 두 동강 내다니…….","JPN":"る、ルナ様を一撃で真っ二つにするなんて……","ENG":"I-it cut right through Ms. Luna with one slash...","TWN":"居…居然一下子就把露娜劈成兩半了……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"쏴라! 다들 죽을 힘을 다해 쏴!!","JPN":"撃て！　全員、死ぬ気で撃て！！","ENG":"FIRE!! Kill it with everything you've got!","TWN":"開槍！大家拼盡全力！！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아, 하아……! 겨우 이거 조금 뛴다고 숨이 차다니……!","JPN":"はあ、はあ……！　ほんの少し走っただけで息が上がるなんて……！","ENG":"*Huff...* *Huff...* I am already out of breath after running only this much?","TWN":"呼呼，呼呼……！才跑了一下就上氣不接下氣的……！"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"이러다 쓰러지시겠어요. 역시 좀 더 쉬셔야 했는데.","JPN":"このままでは倒れてしまいます。やっぱりもっと療養が必要でしたのに。","ENG":"Your legs are about to give. We should've just taken you back to your bed.","TWN":"這樣下去你會暈倒的。還是再休息一下吧。"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쉴 틈이 어디 있어요! 저런 괴물이 날뛰는 마당에!","JPN":"休んでいる暇がどこにあるのですか！　あのような怪物が暴れているのに！","ENG":"There is no time for rest! There is a monster chasing after us!","TWN":"現在哪有時間休息！那個怪物追過來了！"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님? 어디 가세요?! 같이 가요!","JPN":"副学会長様？　どちらに行かれるのですか！？　私も一緒に行きます！","ENG":"Ma'am? Where are you going?! Wait for me!","TWN":"副學會長？你去哪兒？！等等我！"},"stage":{"bg":"CORRIDOR_07","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 연구실이었군요. 항상 이상한 소리가 들리던 곳이.","JPN":"やはり研究室だったのですね。いつも妙な音が聞こえてきた場所は。","ENG":"I knew this place was a laboratory. So this is where all the weird sounds came from.","TWN":"果然是研究室。這裡就是一直傳出奇怪聲音的地方。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그만두세요, 부학회장님. 괴물이 언제 다시 쫓아올지 모르잖아요.","JPN":"やめましょう、副学会長様。怪物がいつまた追ってくるかわかりません。","ENG":"You must stop, ma'am. We don't know when that monster will chase after us again.","TWN":"先別管這個了，副學會長。怪物說不定什麼時候又追過來。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일리 있는 지적입니다. 그러니 더욱 더 누군가 잡혀 있다면 그냥 두고 갈 수 없어요.","JPN":"一理ある指摘です。ですからなおさら、誰かが閉じ込められているのなら放っておけませんわ。","ENG":"Good point. That is why I cannot leave without checking to see if anyone is in here.","TWN":"你說的有道理。所以，如果有人被困在這裡，就更不應該丟下不管。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"실례합니다! 아무도 안 계시나요?!","JPN":"失礼いたします！　誰がいますか！？","ENG":"Excuse me! Is anybody in here?!","TWN":"打擾一下！這裡有沒有人？！"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>성문 확인: 레지나 맥크레디. 대기 모드 해제.</color>","JPN":"<color=#ffd34c>声紋確認：レジーナ・マクレディー。待機モード解除。</color>","ENG":"<color=#ffd34c>Voice recognition confirmed. Regina MacCready. Standby mode disabled.</color>","TWN":"<color=#ffd34c>語音確認：蕾佳娜·麥克蕾蒂，待機模式解除。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오오, 거기 누구 있나? 이쪽일세.","JPN":"おお、そこに誰かいるのか？　こっちだ。","ENG":"Oh, is someone there? Over here!","TWN":"噢噢，誰在那裡？我在這邊。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 제 우려가 적중했군요. 이럴 줄 알았어요.","JPN":"やはり私の心配が的中しましたね。こうなると思っていましたわ。","ENG":"Just as I expected. I knew someone was in here.","TWN":"果然我的擔心是對的。我就知道會這樣。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데……","JPN":"ですが……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 이 새가 말을 한 건가요?","JPN":"副学会長様、この鳥がしゃべったのでしょうか？","ENG":"Vice President? Did that bird just talk?","TWN":"副學會長，是這隻鳥在說話嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"글쎄요……. 새치고는 무척 개성적으로 생겼네요.","JPN":"さあ……鳥にしては随分と個性的な形をしていますわね。","ENG":"Hmm... It looks like a rather peculiar bird if you ask me.","TWN":"不知道……這隻鳥它長得很有個性呢。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"새보다는 사장이라고 불러 주게. 그 편이 익숙해서 말일세.","JPN":"鳥と言わずに社長と呼んでくれたまえ。その方が慣れているからな。","ENG":"Call me Boss instead of bird. I'm more used to that.","TWN":"比起鳥這個稱呼，還是叫我老闆吧。我更習慣這個稱呼。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"아. 네, 사장님. 저는 실키라고 불러 주세요. 여기 계신 분의 간병인이에요.","JPN":"あ。はい、社長。私のことはシルキーとお呼びください。こちらにいらっしゃるお方の看病人です。","ENG":"O-oh, okay, Boss. My name is Sylkie. I'm her caregiver.","TWN":"啊，好，老闆。我叫思琪。我是副學會長的看護。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"레지나 맥크레디입니다. 따지고 싶은 게 한두 가지가 아니지만……","JPN":"レジーナ・マクレディーです。突っこみどころは山ほどありますが……","ENG":"Regina MacCready. I have several points I would like to make, but...","TWN":"我是蕾佳娜·麥克蕾蒂。雖然我有一肚子的問題想問……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저희는 지금 어떤 괴물에게 쫓기고 있는 신세예요.","JPN":"私たちは今、ある怪物に追われていますの。","ENG":"Right now, we are being chased by some monster.","TWN":"但現在我們正在被某種怪物追殺。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"서둘러 이 지긋지긋한 곳을 빠져나가야 합니다. 혹시 출구가 어디 있는지 알고 계시나요?","JPN":"一刻も早くこのうんざりした場所から抜け出さなければいけません。ひょっとして出口がどこにあるかご存じでしょうか。","ENG":"We need to get out of here, fast. Do you happen to know where the exit is?","TWN":"必須趕快逃出這個讓人討厭的地方。你知道出口在哪裡嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 질문에 대답해 주기 전에 나도 한 가지만 묻지.","JPN":"うむ、質問に答える前に私からも一つだけ聞こう。","ENG":"Hmm... Before I answer that, let me ask you a question.","TWN":"呃嗯，在回答你的問題之前，我也想問你一個問題。"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혹시 그 괴물이라는 게, 뒤에 서 있는 저 덩치 말인가?","JPN":"その怪物というのは、後ろに立っているあいつことかね？","ENG":"This monster you talk about, is it that burly creature right behind you?","TWN":"你說的怪物，是站在你後面的那個東西嗎？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...Huh?","TWN":"……什麼？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레지. 나. 찾았. 다.</color>","JPN":"<color=#ff3636>レジー、ナ、見ツケ、タ。</color>","ENG":"<color=#ff3636>I found. You. Regi. Na.</color>","TWN":"<color=#ff3636>蕾佳·娜·找到·了。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉?!","JPN":"ひっ！？","ENG":"Heek?","TWN":"唔？！"},"stage":{"bg":"LABORATORY_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>도. 망치. 면……</color>","JPN":"<color=#ff3636>逃、ゲタ、ラ……</color>","ENG":"<color=#ff3636>If. You. Run...</color>","TWN":"<color=#ff3636>不·可以·逃……</color>"},"stage":{"bg":"LABORATORY_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L38_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>죽어.</color>","JPN":"<color=#ff3636>死ヌ。</color>","ENG":"<color=#ff3636>You. Die.</color>","TWN":"<color=#ff3636>會死。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"}]`);export{e as default};